import re as _re
def _splice_and_renumber():
    for bab in BAB:
        no = bab["no"]
        isi = bab["isi"]
        # sisipkan EXTRA sebelum heading 'Refleksi Mahasiswa'
        if no in EXTRA:
            idx = next((i for i, (k, t) in enumerate(isi) if k == "h2" and "Refleksi Mahasiswa" in t), len(isi))
            isi = isi[:idx] + EXTRA[no] + isi[idx:]
        # renumber semua h2 secara berurutan: {no}.{n}
        n = 0
        new = []
        for k, t in isi:
            if k == "h2":
                n += 1
                t2 = _re.sub(r"^\s*\d+\.\d+\s+", "", t)  # buang prefix lama jika ada
                t = f"{no}.{n} {t2}"
            new.append((k, t))
        bab["isi"] = new

_splice_and_renumber()


